// Decide how many pages to scrape.
// On first run (no seen URLs stored yet), scrape all pages (up to MAX_PAGES).
// On subsequent runs, scrape only page 1 to catch the latest releases.

const store = $getWorkflowStaticData('global');
const seenUrls = store.seenUrls || [];

const isFirstRun = seenUrls.length === 0;
const MAX_PAGES = isFirstRun ? 50 : 1;  // adjust 50 to however deep you want the first scrape

const pages = [];
for (let i = 0; i < MAX_PAGES; i++) {
  pages.push({
    json: {
      page: i,
      offset: i * 15,   // coreradio uses 15 items per page
      isFirstRun: isFirstRun
    }
  });
}

return pages;

// Ported from Python CoreRadioClient - uses the same logic that is proven to work.
// The site uses DataLife Engine (DLE). Each release block contains:
//   - an <img> whose alt attribute holds the full title "Band - Album [type] (year)"
//   - nearby text with "Genre:", "Country:", "Quality:"
//   - an <a href> pointing to the release page

const const html = $input.first().json.body ?? $input.first().json.data ?? $input.first().json.html ?? $input.first().json.text ?? '';

// ── Helpers ──────────────────────────────────────────────────────────────────

function parseTitle(raw) {
  // Remove backslash escapes
  raw = raw.replace(/\\/g, '');
  // Try dash variants
  for (const sep of [' - ', ' \u2013 ', ' \u2014 ']) {
    const idx = raw.indexOf(sep);
    if (idx !== -1) {
      const band  = raw.slice(0, idx).trim();
      const rest  = raw.slice(idx + sep.length).trim();
      // Extract [type] and (year) from the rest
      const typeMatch = rest.match(/\[([^\]]+)\]/);
      const yearMatch = rest.match(/\((\d{4})\)/);
      // Clean album: remove trailing [type] and (year)
      const album = rest.replace(/\s*\[[^\]]+\]\s*/, '').replace(/\s*\(\d{4}\)\s*/, '').trim();
      return {
        band,
        album,
        type: typeMatch ? typeMatch[1] : '',
        year: yearMatch ? yearMatch[1] : new Date().getFullYear().toString()
      };
    }
  }
  return { band: raw.trim(), album: 'Unknown', type: '', year: new Date().getFullYear().toString() };
}

function extractMeta(text) {
  const genreMatch   = text.match(/Genre:\s*(.+?)(?:Country:|Quality:|$)/s);
  const countryMatch = text.match(/Country:\s*(.+?)(?:Quality:|$)/s);
  const qualityMatch = text.match(/Quality:\s*(.+?)$/s);

  const genres = genreMatch
    ? genreMatch[1].split(/[\/,]/).map(g => g.trim()).filter(Boolean)
    : [];

  return {
    genres,
    genre:   genres.join(', ') || 'Unknown',
    country: countryMatch ? countryMatch[1].trim() : 'Unknown',
    quality: qualityMatch ? qualityMatch[1].trim() : 'Unknown',
  };
}

// ── Parse ─────────────────────────────────────────────────────────────────────

// Split HTML into chunks around every occurrence of "Genre:" so we operate
// on individual release blocks rather than the whole page at once.
// Each chunk starts just before an img and ends before the next Genre: block.

const releases = [];

// Find all img alt values that look like "Band - Album" titles
const imgAltRegex = /<img[^>]+alt="([^"]*\s[-\u2013\u2014]\s[^"]+)"[^>]*>/gi;
let imgMatch;

while ((imgMatch = imgAltRegex.exec(html)) !== null) {
  const altText  = imgMatch[1];
  const imgStart = imgMatch.index;

  // Only process alts that look like titles (contain " - " or dashes)
  if (!altText.match(/\s[-\u2013\u2014]\s/)) continue;

  // Grab a window of HTML around this img to find metadata (up to 2000 chars ahead)
  const window = html.slice(imgStart, imgStart + 2000);

  // Skip if no Genre: in this window
  if (!/Genre:/i.test(window)) continue;

  // Extract cover URL from this same img tag
  const srcMatch = imgMatch[0].match(/(?:data-src|src)="([^"]+)"/i);
  const coverUrl = srcMatch ? srcMatch[1] : '';

  // Skip placeholder images
  if (coverUrl.includes('no_image') || coverUrl.includes('coredark')) continue;

  // Find nearest <a href> before or after the img (within the window)
  const linkMatch = window.match(/<a\s+(?:[^>]*\s+)?href="([^"]+)"/i);
  const postUrl   = linkMatch ? linkMatch[1] : '';

  // Extract plain text for metadata (strip tags)
  const plainText = window.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

  const { band, album, type, year } = parseTitle(altText);
  const { genre, genres, country, quality } = extractMeta(plainText);

  releases.push({
    json: {
      artist:    band,
      track:     album,
      type,
      year,
      genre,
      genres,
      country,
      quality,
      imageUrl:  coverUrl,
      sourceUrl: postUrl || 'https://coreradio.online/',
      fullTitle: altText,
      scrapedAt: new Date().toISOString()
    }
  });
}

if (releases.length === 0) {
  // Surface a debug item so you can inspect the raw HTML in n8n
  return [{ json: { debug: true, htmlSnippet: html.slice(0, 500) } }];
}

return releases;

// Deduplicate: only pass through releases whose sourceUrl hasn't been seen before.
// Also persists new URLs back into workflow static data.

const store    = $getWorkflowStaticData('global');
const seenUrls = new Set(store.seenUrls || []);

const items  = $input.all();
const newOnes = [];

for (const item of items) {
  const url = item.json.sourceUrl;
  if (!seenUrls.has(url)) {
    seenUrls.add(url);
    newOnes.push(item);
  }
}

// Persist updated set (convert back to array for JSON storage)
store.seenUrls = Array.from(seenUrls);

// If nothing new, return a single sentinel so downstream nodes don't hang
if (newOnes.length === 0) {
  return [{ json: { noNewReleases: true } }];
}

return newOnes;

// Check for favorite bands
const favoriteBands = [
  'vildhjarta', 'allt', 'imminence', 'karmanjakah',
  'humanitys last breath', 'invent animate', 'currents',
  'lorna shore', 'peur', 'before i turn', 'spiritbox',
  'sleep token', 'bring me the horizon'
];

const items   = $input.all();
const results = [];

for (const item of items) {
  const data       = item.json;
  const searchText = (data.artist + ' ' + data.track + ' ' + data.genre).toLowerCase();
  const isFavorite = favoriteBands.some(band => searchText.includes(band));

  results.push({
    json: {
      ...data,
      isFavorite,
      matchReason: isFavorite ? 'Favorite band detected' : 'New release'
    }
  });
}

return results;

